Itinerary
Pick a day to see what’s on.

itinerary = FileAttachment("itinerary.json").json()

typeIcon = ({
  "flight":   "🛫",
  "arrival":  "🛬",
  "food":     "🍽️",
  "drinks":   "🍺",
  "hotel":    "🛎️",
  "sight":    "📍",
  "activity": "🎭",
  "shop":     "🛍️",
  "drive":    "🚗",
})

html`
&lt;ul class="nav nav-tabs" role="tablist"&gt;
  ${itinerary.map((d, i) =&gt; `
    &lt;li class="nav-item" role="presentation"&gt;
      &lt;button class="nav-link${i === 0 ? ' active' : ''}"
              data-bs-toggle="tab"
              data-bs-target="#itin-panel-${i}"
              type="button" role="tab"
              aria-controls="itin-panel-${i}"
              aria-selected="${i === 0 ? 'true' : 'false'}"&gt;
        ${d.emoji}&nbsp;${d.date}
      &lt;/button&gt;
    &lt;/li&gt;
  `).join("")}
&lt;/ul&gt;
&lt;div class="tab-content mt-3"&gt;
  ${itinerary.map((d, i) =&gt; `
    &lt;div class="tab-pane fade${i === 0 ? ' show active' : ''}"
         id="itin-panel-${i}" role="tabpanel"&gt;
      &lt;div class="itinerary-day-header"&gt;
        &lt;span class="itinerary-day-emoji"&gt;${d.emoji}&lt;/span&gt;
        &lt;span class="itinerary-day-title"&gt;${d.date} — ${d.city}&lt;/span&gt;
      &lt;/div&gt;
      &lt;div class="itinerary-timeline"&gt;
        ${d.items.map(item =&gt; `
          &lt;div class="itinerary-item itinerary-type-${item.type}"&gt;
